mapper.select:
SELECT id, user_id, name, cover, address, longitude, latitude, phone, business_hours, category_id, status, create_time, legal_name, shop_images, ST_Distance_Sphere( point(longitude, latitude), point(#{userLng}, #{userLat}) ) AS distance FROM shop WHERE status = 1 AND longitude IS NOT NULL AND latitude IS NOT NULL
AND ST_Distance_Sphere(point(longitude, latitude), point(#{userLng}, #{userLat})) <= #{radius}
AND name LIKE CONCAT('%', #{keyword}, '%')
AND category_id = #{categoryId}
ORDER BY distance ASC
